import { useState } from "react";
import { useTTS } from "../../hooks/useSpeech";

export default function ListeningSection({ listening, onDone, done }) {
  const { speak, stop, speaking } = useTTS();
  const [showScript, setShowScript] = useState(false);
  const [answers, setAnswers] = useState({});
  const [checked, setChecked] = useState(false);

  return (
    <div className="fade-in">
      <h3 className="font-bold text-gray-300 mb-3">🎧 {listening.title}</h3>

      {/* Audio player UI */}
      <div className="bg-gradient-to-br from-blue-300 to-indigo-300 border-2 border-blue-100 rounded-2xl p-5 mb-4 text-center">
        <div className="text-4xl mb-3">{speaking ? "🔊" : "🎙️"}</div>
        <p className="text-xs text-slate-500 font-bold mb-4">
          {speaking
            ? "Playing audio..."
            : "Click play to listen to the conversation"}
        </p>
        <div className="flex justify-center gap-3">
          <button
            onClick={() =>
              speaking
                ? stop()
                : speak(listening.script.replace(/\n/g, " "), 0.88)
            }
            className={`flex items-center gap-2 px-6 py-2.5 rounded-xl text-sm font-bold border-2 transition-all
              ${speaking ? "bg-blue-900 text-white border-blue-900" : " text-blue-900 border-blue-900 hover:bg-blue-900 hover:text-white"}`}
          >
            {speaking ? "⏹ Stop" : "▶ Play Audio"}
          </button>
          <button
            onClick={() => setShowScript((s) => !s)}
            className="px-5 py-2.5 rounded-xl text-sm font-bold border-2 border-slate-300 text-slate-600 bg-white hover:border-blue-300 transition-all"
          >
            {showScript ? "🙈 Hide" : "👁 Script"}
          </button>
        </div>
      </div>

      {/* Script */}
      <div
        className={`transition-all duration-300 overflow-hidden ${showScript ? "max-h-[500px] opacity-100" : "max-h-0 opacity-0"}`}
      >
        <div className="bg-[#221f35] border border-gray-700 rounded-2xl p-4 text-sm text-slate-300 leading-8 mb-4 space-y-1">
          {listening.script
            .split("\n")
            .map((line, i) =>
              line.trim() ? <p key={i}>{line}</p> : <br key={i} />,
            )}
        </div>
      </div>

      {/* Comprehension */}
      {listening.comprehension && (
        <div className="border-t border-gray-700 pt-4 mt-2">
          <p className="text-sm font-extrabold text- mb-3">
            Comprehension Check
          </p>
          <div className="space-y-4">
            {listening.comprehension.map((cq, i) => (
              <div key={i}>
                <p className="text-sm font-bold text-slate-800 mb-2">
                  {i + 1}. {cq.q}
                </p>
                <div className="grid grid-cols-2 gap-2">
                  {cq.opts.map((opt, j) => {
                    let cls =
                      "text-left px-3 py-2 rounded-lg text-xs font-bold border-2 cursor-pointer transition-all ";
                    if (!checked)
                      cls +=
                        answers[i] === j
                          ? "border-blue-900 bg-blue-50 text-blue-900"
                          : "border-slate-200 bg-white text-slate-600 hover:border-blue-300";
                    else if (j === cq.ans)
                      cls += "border-green-500 bg-green-50 text-green-700";
                    else if (answers[i] === j)
                      cls += "border-red-400 bg-red-50 text-red-700";
                    else
                      cls +=
                        "border-slate-100 bg-slate-50 text-slate-400 opacity-50";
                    return (
                      <button
                        key={j}
                        className={cls}
                        onClick={() =>
                          !checked && setAnswers((a) => ({ ...a, [i]: j }))
                        }
                      >
                        {opt}
                      </button>
                    );
                  })}
                </div>
              </div>
            ))}
            {!checked &&
              Object.keys(answers).length ===
                listening.comprehension.length && (
                <button
                  onClick={() => setChecked(true)}
                  className="bg-indigo-700 text-white px-5 py-2 rounded-xl text-sm font-bold hover:bg-indigo-600 transition-all"
                >
                  Check Answers
                </button>
              )}
          </div>
        </div>
      )}

      {!done ? (
        <div className="flex justify-end mt-5">
          <button
            onClick={onDone}
            className="bg-blue-900 hover:bg-blue-800 text-white font-bold px-8 py-3 rounded-xl text-sm transition-all hover:-translate-y-0.5"
          >
            Mark as Done ✓
          </button>
        </div>
      ) : (
        <p className="text-right text-green-700 font-bold text-sm mt-4">
          ✓ Listening completed!
        </p>
      )}
    </div>
  );
}
